const PASSIVE_EX1 = [{"id": 1, "type": "fill", "q": "Baseball__________with nine players on the team.", "vi": "Bóng chày được chơi với chín cầu thủ trong đội.", "opts": ["A. is played", "B. have been played", "C. are played", "D. has been played"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. is played</div><div class=\"ex-card mb-2\">Baseball<b>is played</b>with nine players on the team.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bóng chày được chơi với chín cầu thủ trong đội.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. is played</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Baseball\" (môn bóng chày, danh từ số ít) + sự thật chung/quy tắc trò chơi → hiện tại đơn bị động \"is played\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. have been played</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have been played\" (hiện tại hoàn thành) không phù hợp diễn tả một quy tắc/sự thật chung.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. are played</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ \"baseball\" số ít, không thể dùng \"are\" (số nhiều).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been played</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been played\" (hiện tại hoàn thành) không phù hợp diễn tả quy tắc chung, chỉ nên dùng hiện tại đơn.</span></div>"}, {"id": 2, "type": "fill", "q": "Married women__________to pursue a career of their preference.", "vi": "Phụ nữ đã kết hôn nên được khuyến khích theo đuổi sự nghiệp mà họ yêu thích.", "opts": ["A. must encourage", "B. can encourage", "C. is encouraged", "D. can be encouraged"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. can be encouraged</div><div class=\"ex-card mb-2\">Married women<b>can be encouraged</b>to pursue a career of their preference.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Phụ nữ đã kết hôn nên được khuyến khích theo đuổi sự nghiệp mà họ yêu thích.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must encourage</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là câu chủ động (must + V), trong khi \"married women\" là đối tượng NHẬN hành động khuyến khích (bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. can encourage</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì tương tự, \"can encourage\" là chủ động, không đúng nghĩa (phụ nữ không phải người đi khuyến khích).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. is encouraged</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"married women\" là chủ ngữ số nhiều, không thể dùng \"is\" (số ít).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. can be encouraged</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều + động từ khuyết thiếu \"can\" ở dạng bị động: can be encouraged (nên được khuyến khích).</span></div>"}, {"id": 3, "type": "fill", "q": "This building__________ before the French came.", "vi": "Tòa nhà này đã được xây dựng trước khi người Pháp đến.", "opts": ["A. had been constructed", "B. has been constructed", "C. has constructed", "D. had constructed"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. had been constructed</div><div class=\"ex-card mb-2\">This building<b>had been constructed</b> before the French came.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tòa nhà này đã được xây dựng trước khi người Pháp đến.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ hoàn thành (S + had + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. had been constructed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động xây dựng xảy ra TRƯỚC một mốc thời gian trong quá khứ (\"before the French came\" - quá khứ đơn) → dùng quá khứ hoàn thành bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has been constructed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been constructed\" (hiện tại hoàn thành) không phù hợp khi đã có mốc thời gian quá khứ rõ ràng \"before... came\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has constructed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi tòa nhà là vật bị xây dựng (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. had constructed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (had constructed), tòa nhà không thể tự \"xây dựng\".</span></div>"}, {"id": 4, "type": "fill", "q": "She__________this song several times by me.", "vi": "Cô ấy đã được tôi nghe hát bài hát này nhiều lần.", "opts": ["A. has heard to sing", "B. has been heard to sing", "C. has heard sung", "D. has been heard sung"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. has been heard to sing</div><div class=\"ex-card mb-2\">She<b>has been heard to sing</b>this song several times by me.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cô ấy đã được tôi nghe hát bài hát này nhiều lần.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — động từ chỉ giác quan (S + be + Vp2 + to V)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. has heard to sing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động của động từ chỉ giác quan (S+hear+O+to V ở dạng chủ động không tồn tại theo cách này); ngoài ra câu có \"by me\" chỉ ra cần bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. has been heard to sing</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Bị động của động từ chỉ giác quan: S + be + heard + to V (nguyên mẫu có to) — \"has been heard to sing\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has heard sung</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"has heard sung\" không đúng ngữ pháp cho bị động động từ chỉ giác quan.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been heard sung</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì khi bị động hóa động từ chỉ giác quan, theo sau \"be heard\" phải là \"to V\" (nếu chủ động dùng V-bare) chứ không phải \"sung\".</span></div>"}, {"id": 5, "type": "fill", "q": "A painting__________for more than one million euros last night.", "vi": "Một bức tranh đã được bán với giá hơn một triệu euro tối qua.", "opts": ["A. sold", "B. had been sold", "C. was being sold", "D. was sold"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. was sold</div><div class=\"ex-card mb-2\">A painting<b>was sold</b>for more than one million euros last night.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một bức tranh đã được bán với giá hơn một triệu euro tối qua.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. sold</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi bức tranh là vật ĐƯỢC bán (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. had been sold</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been sold\" (quá khứ hoàn thành) cần có một mốc thời gian quá khứ khác đi kèm để so sánh, không phù hợp ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. was being sold</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was being sold\" (quá khứ tiếp diễn) diễn tả hành động đang diễn ra tại một thời điểm, không phù hợp với \"last night\" chỉ một sự việc đã hoàn tất.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. was sold</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Last night\" (mốc thời gian quá khứ xác định) + bức tranh được bán (bị động) → quá khứ đơn bị động: was sold.</span></div>"}, {"id": 6, "type": "fill", "q": "When he was at school, Vincent__________, and spell, and count! Yet, he enjoyed it so much!", "vi": "Khi còn đi học, Vincent bị bắt phải làm việc, đánh vần và đếm số! Vậy mà cậu ấy lại rất thích điều đó!", "opts": ["A. was made working", "B. has been made working", "C. was made to work", "D. has been made to work"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. was made to work</div><div class=\"ex-card mb-2\">When he was at school, Vincent<b>was made to work</b>, and spell, and count! Yet, he enjoyed it so much!</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Khi còn đi học, Vincent bị bắt phải làm việc, đánh vần và đếm số! Vậy mà cậu ấy lại rất thích điều đó!</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — MAKE (S + be + made + to V)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. was made working</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì bị động của MAKE là \"be made TO V\", không phải \"made working\" (V-ing sai cấu trúc).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has been made working</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì không phù hợp (hiện tại hoàn thành) trong khi ngữ cảnh là quá khứ (\"when he was at school\"); cấu trúc \"working\" cũng sai.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. was made to work</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Ngữ cảnh quá khứ (\"was at school\") + bị động của MAKE (be made to V): was made to work.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been made to work</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì không phù hợp — ngữ cảnh rõ ràng là quá khứ (was at school), không dùng hiện tại hoàn thành.</span></div>"}, {"id": 7, "type": "fill", "q": "Can you tell me if the pool__________now?", "vi": "Bạn có thể cho tôi biết liệu bể bơi có đang được mở cửa không?", "opts": ["A. is being opened", "B. is opened", "C. being opened", "D. opened"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. is being opened</div><div class=\"ex-card mb-2\">Can you tell me if the pool<b>is being opened</b>now?</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn có thể cho tôi biết liệu bể bơi có đang được mở cửa không?</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại tiếp diễn (S + am/is/are + being + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. is being opened</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Now\" (ngay bây giờ) + hành động đang diễn ra → hiện tại tiếp diễn bị động: is being opened.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is opened</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"is opened\" (hiện tại đơn) diễn tả sự thật chung/thói quen, không phù hợp với \"now\" (ngay lúc này).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. being opened</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"is\", không tạo thành câu hoàn chỉnh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. opened</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"be\", không đúng cấu trúc bị động.</span></div>"}, {"id": 8, "type": "fill", "q": "We__________to the party because my parents don't know who Jim and Jack are.", "vi": "Chúng tôi không được phép đi dự tiệc vì bố mẹ tôi không biết Jim và Jack là ai.", "opts": ["A. were not allowed going", "B. were not allowed to go", "C. are not allowed going", "D. are not allowed to go"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. are not allowed to go</div><div class=\"ex-card mb-2\">We<b>are not allowed to go</b>to the party because my parents don't know who Jim and Jack are.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Chúng tôi không được phép đi dự tiệc vì bố mẹ tôi không biết Jim và Jack là ai.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. were not allowed going</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì quá khứ không khớp với \"don't know\" (hiện tại); ngoài ra sau \"allowed\" cần \"to V\" chứ không phải V-ing.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. were not allowed to go</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì quá khứ không khớp với mệnh đề sau dùng hiện tại đơn \"don't know\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. are not allowed going</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau \"be allowed\" phải là \"to V\", không phải V-ing (going).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. are not allowed to go</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Be allowed to V\" ở thì hiện tại đơn, khớp với \"don't know\" (hiện tại): are not allowed to go.</span></div>"}, {"id": 9, "type": "fill", "q": "David __________ a job in Singapore but he turned it down.", "vi": "David đã được đề nghị một công việc ở Singapore nhưng anh ấy đã từ chối.", "opts": ["A. was offered", "B. offers", "C. has offered", "D. was offering"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. was offered</div><div class=\"ex-card mb-2\">David <b>was offered</b> a job in Singapore but he turned it down.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> David đã được đề nghị một công việc ở Singapore nhưng anh ấy đã từ chối.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. was offered</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Sự việc đã xảy ra và kết thúc trong quá khứ (\"turned it down\" - quá khứ đơn), David là người ĐƯỢC đề nghị việc làm → quá khứ đơn bị động: was offered.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. offers</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động thì hiện tại, không phù hợp thì quá khứ và ý nghĩa bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has offered</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has offered\" là chủ động, không đúng nghĩa (David không phải người đi đề nghị việc).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. was offering</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was offering\" là chủ động (quá khứ tiếp diễn), không đúng nghĩa cần thiết ở đây.</span></div>"}, {"id": 10, "type": "fill", "q": "Nowadays, a refining process __________ extract usable fuel from crude oil.", "vi": "Ngày nay, một quy trình lọc dầu được sử dụng để chiết xuất nhiên liệu từ dầu thô.", "opts": ["A. used to", "B. was used to", "C. is used to", "D. is used for"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. is used to</div><div class=\"ex-card mb-2\">Nowadays, a refining process <b>is used to</b> extract usable fuel from crude oil.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Ngày nay, một quy trình lọc dầu được sử dụng để chiết xuất nhiên liệu từ dầu thô.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. used to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"used to\" diễn tả thói quen trong quá khứ (không còn đúng nữa), mâu thuẫn với \"nowadays\" (ngày nay).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was used to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì quá khứ không phù hợp với \"nowadays\" (hiện tại).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. is used to</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Be used to + V(nguyên mẫu)\" (được sử dụng để làm gì) ở thì hiện tại đơn, phù hợp với \"nowadays\": is used to extract.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. is used for</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau \"used for\" phải là V-ing (used for extracting), không phải \"extract\" nguyên mẫu như trong câu.</span></div>"}, {"id": 11, "type": "fill", "q": "An unidentified flying object__________by many observers from around the globe at 9 last night.", "vi": "Một vật thể bay không xác định đã được nhiều người quan sát từ khắp nơi trên thế giới ghi lại lúc 9 giờ tối qua.", "opts": ["A. is being recorded", "B. was being recorded", "C. were recorded", "D. is recorded"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. was being recorded</div><div class=\"ex-card mb-2\">An unidentified flying object<b>was being recorded</b>by many observers from around the globe at 9 last night.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một vật thể bay không xác định đã được nhiều người quan sát từ khắp nơi trên thế giới ghi lại lúc 9 giờ tối qua.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ tiếp diễn (S + was/were + being + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. is being recorded</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với mốc thời gian quá khứ \"last night\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. was being recorded</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"At 9 last night\" (một thời điểm cụ thể trong quá khứ) + hành động đang diễn ra tại thời điểm đó → quá khứ tiếp diễn bị động: was being recorded.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. were recorded</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ \"an unidentified flying object\" số ít, không dùng \"were\" (số nhiều).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. is recorded</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại đơn không phù hợp với mốc thời gian quá khứ đã nêu.</span></div>"}, {"id": 12, "type": "fill", "q": "The course books__________by four CDs.", "vi": "Sách giáo trình được đi kèm với bốn đĩa CD.", "opts": ["A. are accompanied", "B. has been accompanied", "C. was being accompanied", "D. will have accompanied"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. are accompanied</div><div class=\"ex-card mb-2\">The course books<b>are accompanied</b>by four CDs.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Sách giáo trình được đi kèm với bốn đĩa CD.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. are accompanied</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Course books\" số nhiều + sự thật chung về bộ sách → hiện tại đơn bị động: are accompanied.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has been accompanied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều \"course books\" không đi với động từ số ít \"has\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. was being accompanied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was being accompanied\" (quá khứ tiếp diễn) không phù hợp với một sự thật chung, không mang tính thời điểm quá khứ cụ thể.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will have accompanied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (tương lai hoàn thành), không đúng nghĩa và cấu trúc bị động cần thiết.</span></div>"}, {"id": 13, "type": "fill", "q": "The flowers__________by the gardener every evening.", "vi": "Những bông hoa được người làm vườn tưới nước mỗi buổi tối.", "opts": ["A. are watered", "B. were watered", "C. are watering", "D. are being watered"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. are watered</div><div class=\"ex-card mb-2\">The flowers<b>are watered</b>by the gardener every evening.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Những bông hoa được người làm vườn tưới nước mỗi buổi tối.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. are watered</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Every evening\" (mỗi buổi tối - thói quen lặp lại) → hiện tại đơn bị động: are watered.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. were watered</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì quá khứ không phù hợp với \"every evening\" (thói quen ở hiện tại).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. are watering</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi hoa là vật ĐƯỢC tưới (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. are being watered</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"are being watered\" (hiện tại tiếp diễn) diễn tả hành động đang xảy ra ngay lúc nói, không phù hợp với thói quen lặp lại \"every evening\".</span></div>"}, {"id": 14, "type": "fill", "q": "The task__________in less than ten minutes by John yesterday.", "vi": "Nhiệm vụ đã được John hoàn thành trong chưa đầy mười phút vào hôm qua.", "opts": ["A. has been accomplished", "B. was accomplished", "C. had been accomplished", "D. accomplished"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. was accomplished</div><div class=\"ex-card mb-2\">The task<b>was accomplished</b>in less than ten minutes by John yesterday.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Nhiệm vụ đã được John hoàn thành trong chưa đầy mười phút vào hôm qua.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. has been accomplished</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been accomplished\" (hiện tại hoàn thành) không đi cùng mốc thời gian quá khứ xác định \"yesterday\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. was accomplished</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Yesterday\" (mốc thời gian quá khứ xác định) + nhiệm vụ được hoàn thành (bị động) → quá khứ đơn bị động: was accomplished.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. had been accomplished</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been accomplished\" (quá khứ hoàn thành) cần có một mốc thời gian quá khứ khác để so sánh, không có ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. accomplished</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"the task\" là vật ĐƯỢC hoàn thành (cần bị động).</span></div>"}, {"id": 15, "type": "fill", "q": "A new team of detectives__________in to conduct a fresh inquiry.", "vi": "Một đội thám tử mới đã được mời đến để tiến hành một cuộc điều tra mới.", "opts": ["A. had been called", "B. will be call", "C. were called", "D. were being called"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. were called</div><div class=\"ex-card mb-2\">A new team of detectives<b>were called</b>in to conduct a fresh inquiry.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một đội thám tử mới đã được mời đến để tiến hành một cuộc điều tra mới.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. had been called</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been called\" (quá khứ hoàn thành) cần một mốc thời gian quá khứ khác để so sánh, không phù hợp ngữ cảnh đơn giản này.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. will be call</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"Vp2\" — phải là \"will be called\", không phải \"will be call\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. were called</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Sự việc đơn giản đã xảy ra trong quá khứ, đội thám tử là đối tượng ĐƯỢC mời đến → quá khứ đơn bị động: were called (chia theo nghĩa số nhiều của \"detectives\" trong đội).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. were being called</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"were being called\" (quá khứ tiếp diễn) không phù hợp, đây là một sự việc đã xảy ra và hoàn tất, không nhấn mạnh tính đang diễn ra.</span></div>"}, {"id": 16, "type": "fill", "q": "The orchestra__________by Mira Shapur when the lights went out.", "vi": "Dàn nhạc đang được Mira Shapur chỉ huy thì đèn phụt tắt.", "opts": ["A. was conducted", "B. was being conducted", "C. has been conducted", "D. will be conducted"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. was being conducted</div><div class=\"ex-card mb-2\">The orchestra<b>was being conducted</b>by Mira Shapur when the lights went out.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Dàn nhạc đang được Mira Shapur chỉ huy thì đèn phụt tắt.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ tiếp diễn (S + was/were + being + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. was conducted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì quá khứ đơn bị động chỉ diễn tả hành động đã hoàn tất, không phù hợp với hành động đang xảy ra khi một sự việc khác (đèn tắt) xen vào.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. was being conducted</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động đang diễn ra (chỉ huy dàn nhạc) thì một hành động khác (đèn tắt, quá khứ đơn) xen vào → quá khứ tiếp diễn bị động: was being conducted.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has been conducted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been conducted\" (hiện tại hoàn thành) không phù hợp với ngữ cảnh quá khứ rõ ràng \"when the lights went out\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will be conducted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì tương lai không phù hợp với ngữ cảnh quá khứ của câu.</span></div>"}, {"id": 17, "type": "fill", "q": "In 1911 Marie Curie __________ a Nobel Prize in Chemistry in recognition of her discovery of the two elements radium and polonium.", "vi": "Năm 1911, Marie Curie đã được trao Giải Nobel Hóa học để ghi nhận việc bà phát hiện ra hai nguyên tố radium và polonium.", "opts": ["A. being awarded", "B. was awarding", "C. was awarded", "D. awarded"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. was awarded</div><div class=\"ex-card mb-2\">In 1911 Marie Curie <b>was awarded</b> a Nobel Prize in Chemistry in recognition of her discovery of the two elements radium and polonium.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Năm 1911, Marie Curie đã được trao Giải Nobel Hóa học để ghi nhận việc bà phát hiện ra hai nguyên tố radium và polonium.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. being awarded</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"was\", không tạo thành câu hoàn chỉnh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was awarding</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was awarding\" là dạng chủ động (quá khứ tiếp diễn), trong khi Marie Curie là người ĐƯỢC trao giải (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. was awarded</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"In 1911\" (mốc thời gian quá khứ xác định) + Marie Curie được trao giải (bị động) → quá khứ đơn bị động: was awarded.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. awarded</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi cần diễn tả Marie Curie ĐƯỢC trao giải (bị động).</span></div>"}, {"id": 18, "type": "fill", "q": "The soldiers__________up the hill twice.", "vi": "Những người lính đã bị bắt buộc phải diễu hành lên đồi hai lần.", "opts": ["A. made to be marched", "B. were made march", "C. made to march", "D. were made to march"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. were made to march</div><div class=\"ex-card mb-2\">The soldiers<b>were made to march</b>up the hill twice.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Những người lính đã bị bắt buộc phải diễu hành lên đồi hai lần.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — MAKE (S + be + made + to V)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. made to be marched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"were\", và trật tự từ trong cấu trúc bị động của MAKE không đúng.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. were made march</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì bị động của MAKE cần \"to V\" (were made TO march), không phải \"made march\" thiếu \"to\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. made to march</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"were\" để tạo thành câu bị động hoàn chỉnh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. were made to march</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Bị động của MAKE: S + be + made + to V. \"The soldiers\" là đối tượng bị bắt buộc → were made to march.</span></div>"}, {"id": 19, "type": "fill", "q": "A few songs__________by all their friends to celebrate this event.", "vi": "Một vài bài hát đã được tất cả bạn bè của họ cùng hát để ăn mừng sự kiện này.", "opts": ["A. are be singing", "B. are being sung", "C. are singing", "D. are be sung"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. are being sung</div><div class=\"ex-card mb-2\">A few songs<b>are being sung</b>by all their friends to celebrate this event.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một vài bài hát đã được tất cả bạn bè của họ cùng hát để ăn mừng sự kiện này.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại tiếp diễn (S + am/is/are + being + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. are be singing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"are be singing\" không tồn tại trong ngữ pháp tiếng Anh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. are being sung</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động đang diễn ra (hát để ăn mừng) + \"songs\" là vật ĐƯỢC hát → hiện tại tiếp diễn bị động: are being sung.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. are singing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"songs\" là vật ĐƯỢC hát (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. are be sung</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"are be sung\" không tồn tại, sai vị trí trợ động từ \"being\".</span></div>"}, {"id": 20, "type": "fill", "q": "A foreign language__________in a short time.", "vi": "Một ngoại ngữ không thể được học trong thời gian ngắn.", "opts": ["A. could not learn", "B. could be not learn", "C. could not be learned", "D. could be not learned"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. could not be learned</div><div class=\"ex-card mb-2\">A foreign language<b>could not be learned</b>in a short time.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một ngoại ngữ không thể được học trong thời gian ngắn.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. could not learn</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"a foreign language\" là vật ĐƯỢC học (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. could be not learn</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì vị trí \"not\" sai — phải đứng ngay sau động từ khuyết thiếu \"could\", không phải sau \"be\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. could not be learned</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Modal bị động phủ định: S + modal + not + be + Vp2 → could not be learned.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. could be not learned</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì vị trí \"not\" sai — phải là \"could NOT be learned\", không phải \"could be NOT learned\".</span></div>"}, {"id": 21, "type": "fill", "q": "Applicants' skills, ability and knowledge __________ before job offers are made.", "vi": "Kỹ năng, năng lực và kiến thức của ứng viên được kiểm tra trước khi lời mời làm việc được đưa ra.", "opts": ["A. tested", "B. is tested", "C. have tested", "D. are tested"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. are tested</div><div class=\"ex-card mb-2\">Applicants' skills, ability and knowledge <b>are tested</b> before job offers are made.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Kỹ năng, năng lực và kiến thức của ứng viên được kiểm tra trước khi lời mời làm việc được đưa ra.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. tested</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"are\", không tạo thành câu bị động hoàn chỉnh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is tested</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ là danh sách nhiều thứ (skills, ability, knowledge - số nhiều), không dùng \"is\" (số ít).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. have tested</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi các yếu tố này là đối tượng ĐƯỢC kiểm tra (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. are tested</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều (skills, ability, knowledge) + sự thật chung về quy trình tuyển dụng → hiện tại đơn bị động: are tested.</span></div>"}, {"id": 22, "type": "fill", "q": "It stated that no advocate would__________disparaging and derogatory remarks against the presiding judge.", "vi": "Quy định nêu rõ rằng không luật sư nào được phép đưa ra những lời lẽ xúc phạm, hạ thấp đối với thẩm phán chủ tọa.", "opts": ["A. be permitted making", "B. permit to being made", "C. be permitted to make", "D. permit to be made"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. be permitted to make</div><div class=\"ex-card mb-2\">It stated that no advocate would<b>be permitted to make</b>disparaging and derogatory remarks against the presiding judge.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Quy định nêu rõ rằng không luật sư nào được phép đưa ra những lời lẽ xúc phạm, hạ thấp đối với thẩm phán chủ tọa.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. be permitted making</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì bị động của \"permit sb to do sth\" là \"be permitted TO V\", không phải \"permitted making\" (V-ing sai).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. permit to being made</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì trật tự và cấu trúc \"permit to being made\" không đúng ngữ pháp bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. be permitted to make</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Bị động của \"permit sb to do sth\": be permitted to V → be permitted to make.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. permit to be made</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"permit\" ở đây phải chia thành \"be permitted\" (bị động) để hợp chủ ngữ \"no advocate\" là người NHẬN sự cho phép.</span></div>"}, {"id": 23, "type": "fill", "q": "Make sure your hands__________before you have your dinner.", "vi": "Hãy đảm bảo rằng tay của bạn sẽ được rửa sạch trước khi bạn ăn tối.", "opts": ["A. are being cleaned", "B. will have been cleaned", "C. were cleaned", "D. has been cleaned"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. will have been cleaned</div><div class=\"ex-card mb-2\">Make sure your hands<b>will have been cleaned</b>before you have your dinner.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Hãy đảm bảo rằng tay của bạn sẽ được rửa sạch trước khi bạn ăn tối.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Tương lai hoàn thành (S + will + have + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. are being cleaned</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"are being cleaned\" (hiện tại tiếp diễn) không phù hợp diễn tả một hành động cần hoàn tất trước một mốc thời gian trong tương lai.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. will have been cleaned</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động rửa tay cần HOÀN TẤT trước một hành động khác trong tương lai (\"before you have your dinner\") → tương lai hoàn thành bị động: will have been cleaned.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. were cleaned</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì quá khứ không phù hợp với ngữ cảnh câu mệnh lệnh hướng tới tương lai (before you have dinner).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been cleaned</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been cleaned\" (hiện tại hoàn thành) không nhấn mạnh được việc hoàn tất TRƯỚC một mốc tương lai.</span></div>"}, {"id": 24, "type": "fill", "q": "It is suggested that smoking__________in pubs, restaurants, and other public places.", "vi": "Có đề xuất rằng việc hút thuốc nên bị cấm ở quán rượu, nhà hàng và các nơi công cộng khác.", "opts": ["A. should to be banned", "B. should be banned", "C. should ban", "D. should to ban"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. should be banned</div><div class=\"ex-card mb-2\">It is suggested that smoking<b>should be banned</b>in pubs, restaurants, and other public places.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có đề xuất rằng việc hút thuốc nên bị cấm ở quán rượu, nhà hàng và các nơi công cộng khác.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — 7 động từ đặc biệt: suggest/require/order... (It + be + Vp2 + that + S + (should) + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. should to be banned</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau \"should\" là động từ nguyên mẫu không \"to\", không có \"should TO be\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. should be banned</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc với động từ đặc biệt SUGGEST: It + is + suggested + that + S + should + be + Vp2 → should be banned.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. should ban</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"smoking\" là hành động CẦN bị cấm (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. should to ban</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc sai ngữ pháp \"should to ban\" (thừa \"to\", và cần bị động).</span></div>"}, {"id": 25, "type": "fill", "q": "Motor vehicles__________from driving in the town centre.", "vi": "Các phương tiện cơ giới bị cấm lưu thông ở trung tâm thị trấn.", "opts": ["A. are prohibited", "B. was prohibited", "C. has been prohibited", "D. are being prohibited"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. are prohibited</div><div class=\"ex-card mb-2\">Motor vehicles<b>are prohibited</b>from driving in the town centre.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Các phương tiện cơ giới bị cấm lưu thông ở trung tâm thị trấn.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. are prohibited</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều \"motor vehicles\" + quy định chung (sự thật) → hiện tại đơn bị động: are prohibited.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was prohibited</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều không đi với \"was\" (số ít).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has been prohibited</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều không đi với \"has\" (số ít).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. are being prohibited</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"are being prohibited\" (hiện tại tiếp diễn) không phù hợp diễn tả một quy định chung, mang tính lâu dài.</span></div>"}, {"id": 26, "type": "fill", "q": "This button__________while the experiment is in progress.", "vi": "Nút này không được chạm vào trong khi thí nghiệm đang diễn ra.", "opts": ["A. must not touched", "B. must not being touched", "C. must not be touched", "D. must not been touched"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. must not be touched</div><div class=\"ex-card mb-2\">This button<b>must not be touched</b>while the experiment is in progress.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Nút này không được chạm vào trong khi thí nghiệm đang diễn ra.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. must not touched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"be\" — cấu trúc modal bị động cần \"must + not + BE + Vp2\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must not being touched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì phải dùng \"be\" chứ không phải \"being\" sau động từ khuyết thiếu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. must not be touched</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Modal bị động phủ định: S + must + not + be + Vp2 → must not be touched.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. must not been touched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì phải dùng \"be\" (nguyên mẫu) sau động từ khuyết thiếu, không dùng \"been\".</span></div>"}, {"id": 27, "type": "fill", "q": "Her health__________dramatically since she started on this new diet.", "vi": "Sức khỏe của cô ấy đã cải thiện đáng kể kể từ khi cô ấy bắt đầu chế độ ăn kiêng mới này.", "opts": ["A. were improved", "B. has improved", "C. had been improved", "D. has been improving"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. has been improving</div><div class=\"ex-card mb-2\">Her health<b>has been improving</b>dramatically since she started on this new diet.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Sức khỏe của cô ấy đã cải thiện đáng kể kể từ khi cô ấy bắt đầu chế độ ăn kiêng mới này.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. were improved</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"improve\" ở đây mang nghĩa nội động từ (tự cải thiện), không cần và không nên dùng bị động \"were improved\"; hơn nữa chủ ngữ số ít không đi với \"were\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has improved</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì tuy đúng dạng chủ động nhưng chưa nhấn mạnh được tính liên tục của quá trình cải thiện diễn ra \"since\" một thời điểm; đáp án D phù hợp hơn với ngữ cảnh nhấn mạnh quá trình.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. had been improved</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"health\" tự cải thiện (nội động từ), không dùng dạng bị động \"had been improved\"; ngoài ra thì quá khứ hoàn thành không khớp với \"since\" + hiện tại hoàn thành.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. has been improving</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Health\" tự cải thiện dần theo thời gian (since + mốc quá khứ) → hiện tại hoàn thành tiếp diễn (chủ động, vì improve là nội động từ ở đây): has been improving.</span></div>"}, {"id": 28, "type": "fill", "q": "The case__________by the police.", "vi": "Vụ án sắp được cảnh sát điều tra.", "opts": ["A. is going to be investigating", "B. is going to be investigated", "C. is going to investigating", "D. is going to investigated"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. is going to be investigated</div><div class=\"ex-card mb-2\">The case<b>is going to be investigated</b>by the police.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Vụ án sắp được cảnh sát điều tra.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Tương lai gần (S + am/is/are + going to + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. is going to be investigating</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì bị động cần \"be + Vp2\", không phải \"be + V-ing\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. is going to be investigated</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Tương lai gần bị động: S + am/is/are + going to + be + Vp2 → is going to be investigated.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. is going to investigating</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"be\" trước \"investigating\", và cần dạng Vp2 cho bị động chứ không phải V-ing.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. is going to investigated</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"be\" — cấu trúc đúng phải là \"going to BE investigated\".</span></div>"}, {"id": 29, "type": "fill", "q": "On arrival, you__________an information pack, which is yours to keep.", "vi": "Khi đến nơi, bạn sẽ được nhận một tập tài liệu thông tin, món quà bạn được giữ lại.", "opts": ["A. will be given", "B. are going to be given", "C. were given", "D. have been given"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. will be given</div><div class=\"ex-card mb-2\">On arrival, you<b>will be given</b>an information pack, which is yours to keep.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Khi đến nơi, bạn sẽ được nhận một tập tài liệu thông tin, món quà bạn được giữ lại.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Tương lai đơn (S + will + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. will be given</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"On arrival\" (khi đến, một sự kiện trong tương lai) + bạn là người ĐƯỢC nhận → tương lai đơn bị động: will be given.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. are going to be given</b><br><span style=\"font-weight:400;font-size:13px\">Sai — về ngữ pháp \"are going to be given\" cũng có thể đúng, nhưng \"will\" tự nhiên hơn khi diễn tả một quy trình/thủ tục sẽ xảy ra theo thông lệ (dự đoán mang tính khách quan), phù hợp văn phong trang trọng hơn ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. were given</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì quá khứ không phù hợp với \"on arrival\" mang tính tương lai/hướng dẫn chung.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. have been given</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have been given\" (hiện tại hoàn thành) không phù hợp diễn tả một sự việc SẼ xảy ra trong tương lai.</span></div>"}, {"id": 30, "type": "fill", "q": "The industry__________of having invested little in workers, plant, or infrastructure.", "vi": "Ngành công nghiệp này đã bị cáo buộc là đầu tư quá ít vào công nhân, nhà xưởng, hoặc cơ sở hạ tầng.", "opts": ["A. was accused", "B. have been accused", "C. are accused", "D. will have accused"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. was accused</div><div class=\"ex-card mb-2\">The industry<b>was accused</b>of having invested little in workers, plant, or infrastructure.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Ngành công nghiệp này đã bị cáo buộc là đầu tư quá ít vào công nhân, nhà xưởng, hoặc cơ sở hạ tầng.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. was accused</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"The industry\" (số ít) + sự việc đã xảy ra trong quá khứ (bị cáo buộc) → quá khứ đơn bị động: was accused.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. have been accused</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số ít \"the industry\" không đi với \"have\" (số nhiều).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. are accused</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số ít \"the industry\" không đi với \"are\" (số nhiều).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will have accused</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (tương lai hoàn thành), không đúng ý nghĩa và cấu trúc bị động cần thiết.</span></div>"}, {"id": 31, "type": "fill", "q": "Old chairs in the hall__________with the new ones.", "vi": "Những chiếc ghế cũ trong hội trường đã được thay thế bằng những chiếc ghế mới.", "opts": ["A. have replaced", "B. has replaced", "C. have been replaced", "D. has been replaced"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. have been replaced</div><div class=\"ex-card mb-2\">Old chairs in the hall<b>have been replaced</b>with the new ones.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Những chiếc ghế cũ trong hội trường đã được thay thế bằng những chiếc ghế mới.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have replaced</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"old chairs\" là vật ĐƯỢC thay thế (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has replaced</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều \"chairs\" không đi với động từ số ít \"has\", và đây cũng là dạng chủ động sai nghĩa.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. have been replaced</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều \"old chairs\" + sự việc đã hoàn thành liên quan hiện tại → hiện tại hoàn thành bị động: have been replaced.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been replaced</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều \"chairs\" không đi với \"has\" (số ít).</span></div>"}, {"id": 32, "type": "fill", "q": "Two more car-assembly plants__________by the strike.", "vi": "Hai nhà máy lắp ráp ô tô nữa đã bị đóng cửa do cuộc đình công.", "opts": ["A. had been closed", "B. were closed", "C. has been closed", "D. are being closed"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. were closed</div><div class=\"ex-card mb-2\">Two more car-assembly plants<b>were closed</b>by the strike.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Hai nhà máy lắp ráp ô tô nữa đã bị đóng cửa do cuộc đình công.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. had been closed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been closed\" (quá khứ hoàn thành) cần một mốc thời gian quá khứ khác để so sánh, không có ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. were closed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều \"two more plants\" + hệ quả trực tiếp, đơn giản của cuộc đình công (quá khứ) → quá khứ đơn bị động: were closed.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has been closed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều không đi với động từ số ít \"has\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. are being closed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"are being closed\" (hiện tại tiếp diễn) không phù hợp với ngữ cảnh một sự việc đã xảy ra và hoàn tất trong quá khứ.</span></div>"}, {"id": 33, "type": "fill", "q": "The forest__________for over 30 years before the new law gave it some protection.", "vi": "Khu rừng đã bị chặt phá trong hơn 30 năm trước khi luật mới ra đời bảo vệ nó phần nào.", "opts": ["A. had been cut down", "B. has been cut down", "C. is being cut down", "D. was being cut down"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. had been cut down</div><div class=\"ex-card mb-2\">The forest<b>had been cut down</b>for over 30 years before the new law gave it some protection.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Khu rừng đã bị chặt phá trong hơn 30 năm trước khi luật mới ra đời bảo vệ nó phần nào.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ hoàn thành (S + had + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. had been cut down</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động chặt phá kéo dài xảy ra TRƯỚC một mốc quá khứ khác (\"before the new law gave\" - quá khứ đơn) → quá khứ hoàn thành bị động: had been cut down.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has been cut down</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been cut down\" (hiện tại hoàn thành) không phù hợp khi đã có mốc thời gian quá khứ rõ ràng \"before...gave\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. is being cut down</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với ngữ cảnh hoàn toàn ở quá khứ của câu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. was being cut down</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was being cut down\" (quá khứ tiếp diễn) không diễn tả đúng khoảng thời gian kéo dài TRƯỚC một mốc quá khứ khác; cần quá khứ hoàn thành.</span></div>"}, {"id": 34, "type": "fill", "q": "She insisted that the drugs__________on her without her knowledge.", "vi": "Cô ấy khăng khăng rằng ma túy đã bị cài vào người cô ấy mà cô không hề hay biết.", "opts": ["A. are planted", "B. have been planted", "C. had been planted", "D. were being planted"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. had been planted</div><div class=\"ex-card mb-2\">She insisted that the drugs<b>had been planted</b>on her without her knowledge.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cô ấy khăng khăng rằng ma túy đã bị cài vào người cô ấy mà cô không hề hay biết.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ hoàn thành (S + had + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. are planted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với động từ tường thuật ở quá khứ \"insisted\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. have been planted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have been planted\" (hiện tại hoàn thành) không phù hợp về mặt lùi thì khi động từ chính \"insisted\" ở quá khứ.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. had been planted</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động cài ma túy xảy ra TRƯỚC khi cô ấy phát hiện/khăng khăng (quá khứ) → quá khứ hoàn thành bị động: had been planted.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. were being planted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"were being planted\" (quá khứ tiếp diễn) không nhấn mạnh được việc hành động đã xảy ra XONG trước khi bị phát hiện.</span></div>"}, {"id": 35, "type": "fill", "q": "The bomb__________in the station waiting room where there were nearly 500 people.", "vi": "Quả bom đã được đặt trong phòng chờ nhà ga, nơi có gần 500 người.", "opts": ["A. was planted", "B. has been planted", "C. is planted", "D. was being planted"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. was planted</div><div class=\"ex-card mb-2\">The bomb<b>was planted</b>in the station waiting room where there were nearly 500 people.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Quả bom đã được đặt trong phòng chờ nhà ga, nơi có gần 500 người.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. was planted</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Ngữ cảnh quá khứ (\"there were nearly 500 people\" - quá khứ đơn) + quả bom được đặt (sự việc đã hoàn tất) → quá khứ đơn bị động: was planted.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has been planted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been planted\" (hiện tại hoàn thành) không phù hợp với ngữ cảnh hoàn toàn ở quá khứ (there WERE).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. is planted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với ngữ cảnh quá khứ rõ ràng của câu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. was being planted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was being planted\" (quá khứ tiếp diễn, đang diễn ra) không phù hợp bằng quá khứ đơn diễn tả một sự việc đã hoàn tất.</span></div>"}, {"id": 36, "type": "fill", "q": "A commission__________to investigate the problem of inner-city violence.", "vi": "Một ủy ban đã được thành lập để điều tra vấn đề bạo lực ở nội thành.", "opts": ["A. was set up", "B. was being set up", "C. have been set up", "D. had been set up"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. was set up</div><div class=\"ex-card mb-2\">A commission<b>was set up</b>to investigate the problem of inner-city violence.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một ủy ban đã được thành lập để điều tra vấn đề bạo lực ở nội thành.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. was set up</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"A commission\" (số ít) + sự việc đơn giản đã xảy ra trong quá khứ (thành lập) → quá khứ đơn bị động: was set up.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was being set up</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was being set up\" (quá khứ tiếp diễn) không phù hợp, đây là một sự việc đơn giản đã hoàn tất, không nhấn mạnh tính đang diễn ra.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. have been set up</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số ít \"a commission\" không đi với \"have\" (số nhiều).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. had been set up</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been set up\" (quá khứ hoàn thành) cần một mốc thời gian quá khứ khác để so sánh, không có ở đây.</span></div>"}, {"id": 37, "type": "fill", "q": "The advanced classes__________by Jalali for more than six years.", "vi": "Các lớp nâng cao đã được thầy Jalali giảng dạy hơn sáu năm nay.", "opts": ["A. has been taught", "B. will have been taught", "C. had been taught", "D. have been taught"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. have been taught</div><div class=\"ex-card mb-2\">The advanced classes<b>have been taught</b>by Jalali for more than six years.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Các lớp nâng cao đã được thầy Jalali giảng dạy hơn sáu năm nay.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. has been taught</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều \"classes\" không đi với động từ số ít \"has\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. will have been taught</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì tương lai hoàn thành không phù hợp, không có mốc thời gian tương lai nào được nhắc đến.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. had been taught</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been taught\" (quá khứ hoàn thành) cần một mốc thời gian quá khứ khác để so sánh, không có ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. have been taught</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"For more than six years\" (khoảng thời gian kéo dài đến hiện tại) + chủ ngữ số nhiều → hiện tại hoàn thành bị động: have been taught.</span></div>"}, {"id": 38, "type": "fill", "q": "The burglar__________over the fence.", "vi": "Tên trộm bị nhìn thấy đang trèo qua hàng rào.", "opts": ["A. was seen climb", "B. are seen to climb", "C. was seen to climb", "D. has been seen climb"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. was seen to climb</div><div class=\"ex-card mb-2\">The burglar<b>was seen to climb</b>over the fence.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tên trộm bị nhìn thấy đang trèo qua hàng rào.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — động từ chỉ giác quan (S + be + Vp2 + to V)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. was seen climb</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì bị động của động từ chỉ giác quan cần \"to V\" theo sau \"be seen\", không phải V-bare (climb).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. are seen to climb</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số ít \"the burglar\" không đi với \"are\" (số nhiều).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. was seen to climb</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Bị động của động từ chỉ giác quan: S + be + seen + to V → was seen to climb.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been seen climb</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"to\" trước \"climb\" — bị động của động từ chỉ giác quan luôn cần \"to V\".</span></div>"}, {"id": 39, "type": "fill", "q": "Stonehenge__________by at least another thousand visitors by the end of this year.", "vi": "Bãi đá cổ Stonehenge sẽ được ít nhất một nghìn du khách nữa ghé thăm tính đến cuối năm nay.", "opts": ["A. will visited", "B. will have been visited", "C. will be visited", "D. will have been being visiting"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. will have been visited</div><div class=\"ex-card mb-2\">Stonehenge<b>will have been visited</b>by at least another thousand visitors by the end of this year.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bãi đá cổ Stonehenge sẽ được ít nhất một nghìn du khách nữa ghé thăm tính đến cuối năm nay.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Tương lai hoàn thành (S + will + have + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. will visited</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"be\" — cấu trúc bị động cần \"will + be + Vp2\" hoặc dạng hoàn thành đầy đủ.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. will have been visited</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"By the end of this year\" (mốc thời gian hoàn tất trong tương lai) → tương lai hoàn thành bị động: will have been visited.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. will be visited</b><br><span style=\"font-weight:400;font-size:13px\">Sai — \"will be visited\" (tương lai đơn) chưa thể hiện được mốc thời gian HOÀN TẤT \"by the end of this year\", cần thì hoàn thành.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will have been being visiting</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây không phải cấu trúc ngữ pháp tồn tại (kết hợp sai).</span></div>"}, {"id": 40, "type": "fill", "q": "More people__________in service industries than in manufacturing.", "vi": "Ngày nay có nhiều người làm việc trong ngành dịch vụ hơn là trong ngành sản xuất.", "opts": ["A. are now employed", "B. were now employed", "C. have now been employed", "D. will be now employed"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. are now employed</div><div class=\"ex-card mb-2\">More people<b>are now employed</b>in service industries than in manufacturing.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Ngày nay có nhiều người làm việc trong ngành dịch vụ hơn là trong ngành sản xuất.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. are now employed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Now\" (hiện tại) + sự thật đang đúng ở hiện tại → hiện tại đơn bị động: are now employed.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. were now employed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"were\" (quá khứ) mâu thuẫn với \"now\" (hiện tại).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. have now been employed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have now been employed\" không tự nhiên bằng hiện tại đơn khi diễn tả một thực trạng chung ở hiện tại.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will be now employed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"will be\" (tương lai) mâu thuẫn với \"now\" (hiện tại).</span></div>"}, {"id": 41, "type": "fill", "q": "He__________doing 80 miles an hour.", "vi": "Anh ta đã bị bắt vì lái xe với tốc độ 80 dặm một giờ.", "opts": ["A. was caught", "B. is caught", "C. had been caught", "D. will be caught"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. was caught</div><div class=\"ex-card mb-2\">He<b>was caught</b>doing 80 miles an hour.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Anh ta đã bị bắt vì lái xe với tốc độ 80 dặm một giờ.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. was caught</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Sự việc đã xảy ra và hoàn tất trong quá khứ (bị bắt) → quá khứ đơn bị động: was caught.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is caught</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với một sự việc đã xảy ra (bị bắt vì đang chạy quá tốc độ).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. had been caught</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been caught\" (quá khứ hoàn thành) cần một mốc thời gian quá khứ khác để so sánh, không có ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will be caught</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì tương lai không phù hợp với một sự việc đã xảy ra rồi.</span></div>"}, {"id": 42, "type": "fill", "q": "They__________with accepting illegal contributions.", "vi": "Họ đã bị buộc tội nhận các khoản đóng góp bất hợp pháp.", "opts": ["A. are being charged", "B. were charged", "C. has been charged", "D. had been charged"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. were charged</div><div class=\"ex-card mb-2\">They<b>were charged</b>with accepting illegal contributions.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Họ đã bị buộc tội nhận các khoản đóng góp bất hợp pháp.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. are being charged</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"are being charged\" (hiện tại tiếp diễn) không phù hợp bằng quá khứ đơn khi không có ngữ cảnh chỉ rõ \"đang diễn ra\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. were charged</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều \"they\" + sự việc đơn giản đã xảy ra trong quá khứ (bị buộc tội) → quá khứ đơn bị động: were charged.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has been charged</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều \"they\" không đi với động từ số ít \"has\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. had been charged</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been charged\" (quá khứ hoàn thành) cần một mốc thời gian quá khứ khác để so sánh, không có ở đây.</span></div>"}, {"id": 43, "type": "fill", "q": "These lands__________by farmers for as long as we know it.", "vi": "Những vùng đất này đã và đang được nông dân canh tác từ trước đến nay, theo những gì chúng ta biết.", "opts": ["A. were cultivated", "B. have been being cultivated", "C. are cultivated", "D. has been cultivated"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. have been being cultivated</div><div class=\"ex-card mb-2\">These lands<b>have been being cultivated</b>by farmers for as long as we know it.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Những vùng đất này đã và đang được nông dân canh tác từ trước đến nay, theo những gì chúng ta biết.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. were cultivated</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì quá khứ đơn không phù hợp với ý nghĩa \"kéo dài từ quá khứ đến hiện tại\" của \"for as long as we know it\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. have been being cultivated</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động canh tác kéo dài liên tục từ quá khứ đến hiện tại, vẫn đang tiếp diễn → hiện tại hoàn thành tiếp diễn bị động (dạng đầy đủ, nhấn mạnh tính liên tục): have been being cultivated.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. are cultivated</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì hiện tại đơn chỉ nêu sự thật chung, không nhấn mạnh được khoảng thời gian \"for as long as we know it\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been cultivated</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều \"lands\" không đi với động từ số ít \"has\".</span></div>"}, {"id": 44, "type": "fill", "q": "Your password__________with others.", "vi": "Mật khẩu của bạn không được chia sẻ với người khác.", "opts": ["A. mustn't be shared", "B. must be not shared", "C. mustn't share", "D. mustn't shared"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. mustn't be shared</div><div class=\"ex-card mb-2\">Your password<b>mustn't be shared</b>with others.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Mật khẩu của bạn không được chia sẻ với người khác.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. mustn't be shared</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Modal bị động phủ định: S + must + not + be + Vp2 → mustn't be shared.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. must be not shared</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì vị trí \"not\" sai — phải đặt ngay sau \"must\" (mustn't), không phải sau \"be\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. mustn't share</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, thiếu \"be\", trong khi \"password\" là vật ĐƯỢC/KHÔNG ĐƯỢC chia sẻ (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. mustn't shared</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"be\" trước \"shared\" để tạo thành cấu trúc bị động hoàn chỉnh.</span></div>"}, {"id": 45, "type": "fill", "q": "The earth__________by dinosaurs over sixty-five million years ago.", "vi": "Trái đất đã từng bị khủng long chiếm lĩnh cách đây hơn sáu mươi lăm triệu năm.", "opts": ["A. was occupied", "B. was being occupied", "C. has been occupied", "D. has been being occupied"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. was occupied</div><div class=\"ex-card mb-2\">The earth<b>was occupied</b>by dinosaurs over sixty-five million years ago.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Trái đất đã từng bị khủng long chiếm lĩnh cách đây hơn sáu mươi lăm triệu năm.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. was occupied</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Over sixty-five million years ago\" (mốc thời gian quá khứ xác định) → quá khứ đơn bị động: was occupied.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was being occupied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"was being occupied\" (quá khứ tiếp diễn) không phù hợp với một sự thật lịch sử khái quát, không nhấn mạnh tính đang diễn ra tại một thời điểm.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has been occupied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been occupied\" (hiện tại hoàn thành) không đi cùng mốc thời gian quá khứ xác định \"... years ago\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been being occupied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc phức tạp này không phù hợp và không tự nhiên với ngữ cảnh một sự thật lịch sử đơn giản.</span></div>"}];
const PASSIVE_EX2 = [{"id": 1, "type": "fill", "q": "We can't go along here because the road__________.", "vi": "Chúng ta không thể đi qua đây vì con đường đang được sửa chữa.", "opts": ["A. is repairing", "B. is repaired", "C. is being repaired", "D. repairs"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. is being repaired</div><div class=\"ex-card mb-2\">We can't go along here because the road<b>is being repaired</b>.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Chúng ta không thể đi qua đây vì con đường đang được sửa chữa.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại tiếp diễn (S + am/is/are + being + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. is repairing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi con đường là vật ĐƯỢC sửa (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is repaired</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì hiện tại đơn không phù hợp diễn tả một công việc đang diễn ra (lý do không đi qua được ngay lúc này).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. is being repaired</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động sửa đường đang diễn ra tại thời điểm nói (lý do đường bị chặn) → hiện tại tiếp diễn bị động: is being repaired.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. repairs</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động thì hiện tại đơn, không đúng nghĩa và cấu trúc bị động cần thiết.</span></div>"}, {"id": 2, "type": "fill", "q": "The story I've just read__________Agatha Christie.", "vi": "Câu chuyện tôi vừa đọc được viết bởi Agatha Christie.", "opts": ["A. was written", "B. was written by", "C. was written from", "D. wrote by"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. was written by</div><div class=\"ex-card mb-2\">The story I've just read<b>was written by</b>Agatha Christie.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Câu chuyện tôi vừa đọc được viết bởi Agatha Christie.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. was written</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu giới từ \"by\" trước tác giả (tác nhân gây ra hành động) khi nêu tên người thực hiện.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. was written by</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Quá khứ đơn bị động + \"by + tác giả\" để chỉ người viết: was written by Agatha Christie.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. was written from</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì giới từ đúng cho tác nhân trong câu bị động là \"by\", không phải \"from\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. wrote by</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"was\" và cấu trúc chủ động \"wrote by\" không đúng ngữ pháp.</span></div>"}, {"id": 3, "type": "fill", "q": "Why don't you have brother__________the roof?", "vi": "Sao bạn không nhờ anh trai sửa mái nhà đi?", "opts": ["A. repairs", "B. repair", "C. repaired", "D. to repair"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. repair</div><div class=\"ex-card mb-2\">Why don't you have brother<b>repair</b>the roof?</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Sao bạn không nhờ anh trai sửa mái nhà đi?</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — Thể nhờ/bảo: have/get sth done</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. repairs</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau cấu trúc nhờ vả chủ động \"have + sb + V(nguyên mẫu)\", động từ không chia theo chủ ngữ.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. repair</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc nhờ ai đó làm gì (chủ động): S + have + sb + V(bare) → have brother repair (nhờ anh trai sửa).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. repaired</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"repaired\" (Vp2) dùng khi diễn tả bị động \"have + sth + Vp2\" (nhờ SỰ VẬT được sửa), nhưng ở đây tân ngữ là \"brother\" (người), cần V-bare.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. to repair</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"have sb TO V\" không tồn tại — sau \"have + sb\" luôn là V nguyên mẫu không \"to\".</span></div>"}, {"id": 4, "type": "fill", "q": "He was made__________over his head by the robber.", "vi": "Anh ta đã bị tên cướp bắt phải giơ hai tay lên đầu.", "opts": ["A. to hand", "B. handing", "C. hand", "D. handed"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. to hand</div><div class=\"ex-card mb-2\">He was made<b>to hand</b>over his head by the robber.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Anh ta đã bị tên cướp bắt phải giơ hai tay lên đầu.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — MAKE (S + be + made + to V)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. to hand</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Bị động của MAKE: S + be + made + to V → was made to hand (over his head - giơ tay lên đầu).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. handing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"made handing\" (V-ing) không đúng với bị động của MAKE.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. hand</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"to\" — bị động của MAKE luôn cần \"to V\" (khác với chủ động dùng V-bare).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. handed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"handed\" (Vp2) không đúng cấu trúc bị động của MAKE, vốn cần \"to V\".</span></div>"}, {"id": 5, "type": "fill", "q": "Something funny__________in class yesterday.", "vi": "Có một chuyện buồn cười đã xảy ra trong lớp học hôm qua.", "opts": ["A. happened", "B. was happened", "C. happens", "D. is happened"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. happened</div><div class=\"ex-card mb-2\">Something funny<b>happened</b>in class yesterday.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có một chuyện buồn cười đã xảy ra trong lớp học hôm qua.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Lưu ý — nội động từ (happen, occur...) KHÔNG có dạng bị động</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. happened</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Happen\" (xảy ra) là NỘI ĐỘNG TỪ, không có dạng bị động, và \"yesterday\" chỉ mốc quá khứ → quá khứ đơn chủ động: happened.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was happened</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"happen\" là nội động từ, không có dạng bị động \"was happened\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. happens</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với mốc thời gian quá khứ \"yesterday\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. is happened</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"happen\" là nội động từ, không có dạng bị động \"is happened\".</span></div>"}, {"id": 6, "type": "fill", "q": "Many U.S automobiles__________in Detroit, Michigan.", "vi": "Nhiều ô tô của Mỹ được sản xuất tại Detroit, Michigan.", "opts": ["A. manufacture", "B. have manufactured", "C. are manufactured", "D. are manufacturing"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. are manufactured</div><div class=\"ex-card mb-2\">Many U.S automobiles<b>are manufactured</b>in Detroit, Michigan.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Nhiều ô tô của Mỹ được sản xuất tại Detroit, Michigan.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. manufacture</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"automobiles\" là vật ĐƯỢC sản xuất (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. have manufactured</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (hiện tại hoàn thành), không đúng nghĩa cần bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. are manufactured</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều \"automobiles\" + sự thật chung → hiện tại đơn bị động: are manufactured.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. are manufacturing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (hiện tại tiếp diễn), không đúng nghĩa cần bị động.</span></div>"}, {"id": 7, "type": "fill", "q": "A lot of pesticide residue can__________on unwashed products.", "vi": "Rất nhiều dư lượng thuốc trừ sâu có thể được tìm thấy trên các sản phẩm chưa rửa.", "opts": ["A. find", "B. found", "C. be finding", "D. be found"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. be found</div><div class=\"ex-card mb-2\">A lot of pesticide residue can<b>be found</b>on unwashed products.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Rất nhiều dư lượng thuốc trừ sâu có thể được tìm thấy trên các sản phẩm chưa rửa.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. find</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"dư lượng thuốc trừ sâu\" là vật ĐƯỢC tìm thấy (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. found</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau động từ khuyết thiếu \"can\" cần V-bare hoặc \"be + Vp2\", không dùng trực tiếp Vp2 \"found\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. be finding</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì modal bị động cần \"be + Vp2\", không phải \"be + V-ing\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. be found</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Modal bị động: S + can + be + Vp2 → can be found.</span></div>"}, {"id": 8, "type": "fill", "q": "We__________by a loud noise last night.", "vi": "Chúng tôi đã bị đánh thức bởi một tiếng ồn lớn tối qua.", "opts": ["A. woke up", "B. are woken up", "C. were woken up", "D. were walking up"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. were woken up</div><div class=\"ex-card mb-2\">We<b>were woken up</b>by a loud noise last night.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Chúng tôi đã bị đánh thức bởi một tiếng ồn lớn tối qua.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. woke up</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"we\" là người ĐƯỢC/BỊ đánh thức bởi tiếng ồn (cần bị động, có \"by\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. are woken up</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với mốc thời gian quá khứ \"last night\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. were woken up</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Last night\" (quá khứ) + \"by a loud noise\" (tác nhân) → quá khứ đơn bị động: were woken up.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. were walking up</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"walking up\" (đi bộ lên) sai nghĩa, từ đúng phải là \"woken up\" (thức dậy).</span></div>"}, {"id": 9, "type": "fill", "q": "How did that window__________? ~ I don't know.", "vi": "Cái cửa sổ đó đã bị vỡ bằng cách nào vậy? ~ Tôi không biết.", "opts": ["A. get broken", "B. broken", "C. got broken", "D. was broken"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. get broken</div><div class=\"ex-card mb-2\">How did that window<b>get broken</b>? ~ I don't know.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Cái cửa sổ đó đã bị vỡ bằng cách nào vậy? ~ Tôi không biết.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — get + Vp2 (thay cho be + Vp2, thường dùng trong câu hỏi/khẩu ngữ)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. get broken</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Câu hỏi dùng trợ động từ \"did\" nên động từ chính (get) phải ở dạng nguyên mẫu: How did...get broken?</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. broken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"get\"/\"be\" để tạo dạng bị động, \"broken\" đứng một mình không tạo thành động từ hoàn chỉnh sau \"did\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. got broken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đã có trợ động từ \"did\" chia thì rồi, động từ theo sau phải ở dạng nguyên mẫu \"get\", không chia thành \"got\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. was broken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đã dùng \"did\" (trợ động từ nghi vấn quá khứ), không thể lặp lại chia thì ở \"was\" nữa.</span></div>"}, {"id": 10, "type": "fill", "q": "Some film stars__________difficult to work with.", "vi": "Một số ngôi sao điện ảnh được cho là khó làm việc cùng.", "opts": ["A. are said to", "B. are said to be", "C. say to he", "D. said to be"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. are said to be</div><div class=\"ex-card mb-2\">Some film stars<b>are said to be</b>difficult to work with.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một số ngôi sao điện ảnh được cho là khó làm việc cùng.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — động từ chỉ quan điểm: S + be + said/believed... + to V</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. are said to</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"be\" trước tính từ \"difficult\" — cấu trúc cần \"be said to BE + adj\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. are said to be</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc bị động với động từ chỉ quan điểm + tính từ: S + be + said + to be + adj → are said to be difficult.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. say to he</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"say to he\" hoàn toàn sai ngữ pháp (chủ động, đại từ sai vị trí).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. said to be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"are\" ở đầu để tạo thành câu bị động hoàn chỉnh.</span></div>"}, {"id": 11, "type": "fill", "q": "Last night a tornado swept through Rockville. It__________ everything in its path.", "vi": "Tối qua một cơn lốc xoáy đã quét qua Rockville. Nó đã phá hủy mọi thứ trên đường đi của nó.", "opts": ["A. destroyed", "B. was destroyed", "C. was being destroyed", "D. has been destroyed"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. destroyed</div><div class=\"ex-card mb-2\">Last night a tornado swept through Rockville. It<b>destroyed</b> everything in its path.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tối qua một cơn lốc xoáy đã quét qua Rockville. Nó đã phá hủy mọi thứ trên đường đi của nó.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. destroyed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"It\" = cơn lốc xoáy, CHÍNH nó là tác nhân gây ra sự phá hủy → câu chủ động, quá khứ đơn: destroyed.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. was destroyed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng bị động, nhưng \"it\" (cơn lốc) là chủ thể gây ra hành động (chủ động), không phải vật bị phá hủy.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. was being destroyed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì tương tự, đây là dạng bị động không đúng vai trò chủ ngữ \"it\" (tác nhân).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has been destroyed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been destroyed\" là bị động, không đúng vai trò chủ ngữ; ngoài ra thì cũng không khớp \"last night\".</span></div>"}, {"id": 12, "type": "fill", "q": "Vitamin C__________by the human body. It gets into the bloodstream quickly.", "vi": "Vitamin C được cơ thể con người hấp thụ dễ dàng. Nó nhanh chóng đi vào máu.", "opts": ["A. absorbs easily", "B. is easily absorbing", "C. is easily absorbed", "D. absorbed easily"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. is easily absorbed</div><div class=\"ex-card mb-2\">Vitamin C<b>is easily absorbed</b>by the human body. It gets into the bloodstream quickly.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Vitamin C được cơ thể con người hấp thụ dễ dàng. Nó nhanh chóng đi vào máu.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. absorbs easily</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"Vitamin C\" là chất ĐƯỢC hấp thụ (cần bị động, có \"by the human body\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is easily absorbing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"is easily absorbing\" là dạng chủ động (hiện tại tiếp diễn), không đúng nghĩa cần bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. is easily absorbed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"By the human body\" (tác nhân) + sự thật chung → hiện tại đơn bị động: is easily absorbed.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. absorbed easily</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (quá khứ đơn), không phù hợp thì hiện tại của sự thật khoa học và cần bị động.</span></div>"}, {"id": 13, "type": "fill", "q": "Why did Tom keep making jokes about me? I don't enjoy__________at.", "vi": "Tại sao Tom cứ trêu chọc tôi vậy? Tôi không thích bị cười nhạo.", "opts": ["A. be laugh", "B. to be laughed", "C. laughing", "D. being laughed"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. being laughed</div><div class=\"ex-card mb-2\">Why did Tom keep making jokes about me? I don't enjoy<b>being laughed</b>at.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tại sao Tom cứ trêu chọc tôi vậy? Tôi không thích bị cười nhạo.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. be laugh</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"be laugh\" không đúng ngữ pháp; \"enjoy\" cần V-ing theo sau, và cần dạng bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. to be laughed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"enjoy\" đòi hỏi V-ing (gerund) theo sau, không phải \"to V\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. laughing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (laughing - cười), trong khi người nói là đối tượng BỊ cười nhạo (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. being laughed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Enjoy\" + V-ing; và cần bị động vì người nói là đối tượng bị cười nhạo → being laughed (at).</span></div>"}, {"id": 14, "type": "fill", "q": "John__________last week.", "vi": "Tuần trước John đã thuê người sơn lại nhà của mình.", "opts": ["A. had his house painted", "B. had painted his house", "C. had his father to paint", "D. had his house paint"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. had his house painted</div><div class=\"ex-card mb-2\">John<b>had his house painted</b>last week.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tuần trước John đã thuê người sơn lại nhà của mình.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — Thể nhờ/bảo: have/get sth done</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. had his house painted</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Thể nhờ/bảo bị động: S + have + sth + Vp2 → had his house painted (nhờ người khác sơn nhà cho mình).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. had painted his house</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had painted his house\" là quá khứ hoàn thành chủ động (tự John sơn nhà), khác nghĩa với việc NHỜ người khác sơn.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. had his father to paint</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"have sb TO V\" không tồn tại — nếu nhờ người cụ thể (father) làm, cần \"have + sb + V-bare\" (had his father paint), không có \"to\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. had his house paint</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu Vp2 — phải là \"painted\", không phải \"paint\" (nguyên mẫu) trong cấu trúc nhờ vả với tân ngữ là vật (house).</span></div>"}, {"id": 15, "type": "fill", "q": "Today, many serious childhood diseases__________by early immunization.", "vi": "Ngày nay, nhiều bệnh nghiêm trọng ở trẻ em có thể được ngăn ngừa bằng cách tiêm chủng sớm.", "opts": ["A. are preventing", "B. can prevent", "C. prevent", "D. can be prevented"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. can be prevented</div><div class=\"ex-card mb-2\">Today, many serious childhood diseases<b>can be prevented</b>by early immunization.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Ngày nay, nhiều bệnh nghiêm trọng ở trẻ em có thể được ngăn ngừa bằng cách tiêm chủng sớm.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. are preventing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"diseases\" là đối tượng ĐƯỢC ngăn ngừa (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. can prevent</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, không đúng nghĩa cần bị động (bệnh không tự ngăn ngừa được).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. prevent</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động thì hiện tại đơn, không đúng nghĩa cần bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. can be prevented</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Modal bị động: S + can + be + Vp2 → can be prevented.</span></div>"}, {"id": 16, "type": "fill", "q": "\"__________about the eight o'clock flight to Chicago?\" \"Not yet.\"", "vi": "\"Đã có thông báo nào về chuyến bay 8 giờ đi Chicago chưa?\" \"Chưa ạ.\"", "opts": ["A. Has been an announcement made", "B. Has an announcement made", "C. Has an announcement been made", "D. Has been made an announcement"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. Has an announcement been made</div><div class=\"ex-card mb-2\">\"<b>Has an announcement been made</b>about the eight o'clock flight to Chicago?\" \"Not yet.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> \"Đã có thông báo nào về chuyến bay 8 giờ đi Chicago chưa?\" \"Chưa ạ.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. Has been an announcement made</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì trật tự từ sai — chủ ngữ \"an announcement\" phải đứng giữa \"Has\" và \"been\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. Has an announcement made</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"been\" — câu hỏi hiện tại hoàn thành bị động cần \"Has + S + been + Vp2\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. Has an announcement been made</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Câu hỏi thì hiện tại hoàn thành bị động: Has + S + been + Vp2 → Has an announcement been made?</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. Has been made an announcement</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì trật tự từ hoàn toàn sai, chủ ngữ phải đứng trước \"been made\", không phải sau.</span></div>"}, {"id": 17, "type": "fill", "q": "\"Has the committee made its decision yet?\" \"Not yet. They are still__________the proposal.\"", "vi": "\"Ủy ban đã đưa ra quyết định chưa?\" \"Chưa. Họ vẫn đang xem xét đề xuất đó.\"", "opts": ["A. considering", "B. been considered", "C. being considered", "D. considered"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. considering</div><div class=\"ex-card mb-2\">\"Has the committee made its decision yet?\" \"Not yet. They are still<b>considering</b>the proposal.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> \"Ủy ban đã đưa ra quyết định chưa?\" \"Chưa. Họ vẫn đang xem xét đề xuất đó.\"</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Lưu ý — nội động từ (happen, occur...) KHÔNG có dạng bị động</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. considering</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"They\" (ủy ban) chính là chủ thể ĐANG xem xét (chủ động, không cần bị động) → hiện tại tiếp diễn chủ động: are still considering.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. been considered</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng bị động (thiếu \"being\"), nhưng \"they\" là chủ thể hành động (chủ động), không phải đối tượng bị xem xét.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. being considered</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì tương tự, đây là dạng bị động không đúng vai trò chủ ngữ \"they\" (chủ thể hành động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. considered</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ để tạo bị động, và về nghĩa \"they\" là người xem xét (chủ động) chứ không phải bị xem xét.</span></div>"}, {"id": 18, "type": "fill", "q": "I might watch this program. It__________very funny.", "vi": "Có thể tôi sẽ xem chương trình này. Nghe nói nó rất buồn cười.", "opts": ["A. suppose to be", "B. is supposed being", "C. is supposed to be", "D. was supposed be"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. is supposed to be</div><div class=\"ex-card mb-2\">I might watch this program. It<b>is supposed to be</b>very funny.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có thể tôi sẽ xem chương trình này. Nghe nói nó rất buồn cười.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — động từ chỉ quan điểm: S + be + said/believed... + to V</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. suppose to be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"is\" ở đầu để tạo thành câu bị động hoàn chỉnh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is supposed being</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau \"be supposed\" phải là \"to be\", không phải \"being\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. is supposed to be</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc bị động với động từ chỉ quan điểm: S + be + supposed + to be + adj → is supposed to be (very funny) - nghe nói/được cho là rất buồn cười.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. was supposed be</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"to\" trước \"be\", và thì quá khứ không khớp với ngữ cảnh hiện tại (\"I might watch\").</span></div>"}, {"id": 19, "type": "fill", "q": "Do you get your heating__________every year?", "vi": "Bạn có nhờ người kiểm tra hệ thống sưởi mỗi năm không?", "opts": ["A. checking", "B. check", "C. be check", "D. checked"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. checked</div><div class=\"ex-card mb-2\">Do you get your heating<b>checked</b>every year?</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Bạn có nhờ người kiểm tra hệ thống sưởi mỗi năm không?</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — Thể nhờ/bảo: have/get sth done</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. checking</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thể nhờ vả bị động \"get sth done\" cần Vp2, không phải V-ing.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. check</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"get sth done\" cần Vp2 (checked), không dùng V-bare (check).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. be check</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"be check\" không tồn tại trong thể nhờ vả này.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. checked</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Thể nhờ/bảo (dạng khác với have): S + get + sth + Vp2 → get your heating checked.</span></div>"}, {"id": 20, "type": "fill", "q": "Claude Jennings is said__________his memory.", "vi": "Người ta nói rằng Claude Jennings đã mất trí nhớ.", "opts": ["A. to have been lost", "B. to be lost", "C. to have lost", "D. to lose"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. to have lost</div><div class=\"ex-card mb-2\">Claude Jennings is said<b>to have lost</b>his memory.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Người ta nói rằng Claude Jennings đã mất trí nhớ.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — động từ chỉ quan điểm: S + be + said/believed... + to V</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. to have been lost</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"his memory\" ở đây là tân ngữ của \"lose\" (Claude TỰ mất trí nhớ - chủ động), không cần dạng bị động \"have been lost\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. to be lost</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"to be lost\" (bị động) không đúng — Claude là người CHỦ ĐỘNG mất trí nhớ của chính mình (\"lose one's memory\" là cụm chủ động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. to have lost</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Hành động mất trí nhớ đã xảy ra TRƯỚC thời điểm nói (is said) → to have + Vp2 (chủ động, vì \"his memory\" là tân ngữ trực tiếp của \"lose\"): to have lost.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. to lose</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cần dạng hoàn thành \"to have lost\" để chỉ việc mất trí nhớ đã xảy ra trước khi người ta nói về nó, không dùng \"to lose\" (nguyên mẫu đơn).</span></div>"}, {"id": 21, "type": "fill", "q": "A new campaign____________to promote safe driving.", "vi": "Một chiến dịch mới đã được phát động để thúc đẩy lái xe an toàn.", "opts": ["A. has been launched", "B. has been launching", "C. were launched", "D. had been launched"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. has been launched</div><div class=\"ex-card mb-2\">A new campaign<b>has been launched</b>__to promote safe driving.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Một chiến dịch mới đã được phát động để thúc đẩy lái xe an toàn.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. has been launched</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"A new campaign\" (số ít) + sự việc vừa hoàn thành, còn liên quan hiện tại → hiện tại hoàn thành bị động: has been launched.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has been launching</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì bị động cần \"been + Vp2\", không phải \"been + V-ing\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. were launched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số ít \"a new campaign\" không đi với \"were\" (số nhiều).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. had been launched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been launched\" (quá khứ hoàn thành) cần một mốc thời gian quá khứ khác để so sánh, không có ở đây.</span></div>"}, {"id": 22, "type": "fill", "q": "The Olympic Games________on television by millions of people worldwide.", "vi": "Thế vận hội Olympic được hàng triệu người trên khắp thế giới xem qua truyền hình.", "opts": ["A. have watched", "B. are watched", "C. will be watching", "D. will have watched"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. are watched</div><div class=\"ex-card mb-2\">The Olympic Games<b>are watched</b>on television by millions of people worldwide.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Thế vận hội Olympic được hàng triệu người trên khắp thế giới xem qua truyền hình.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have watched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"the Olympic Games\" là đối tượng ĐƯỢC xem (cần bị động, có \"by\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. are watched</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Sự thật chung + \"by millions of people\" (tác nhân) → hiện tại đơn bị động: are watched.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. will be watching</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (tương lai tiếp diễn), không đúng nghĩa cần bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. will have watched</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (tương lai hoàn thành), không đúng nghĩa cần bị động.</span></div>"}, {"id": 23, "type": "fill", "q": "Mary's aunt__________in hospital for some more tests.", "vi": "Dì của Mary đang được giữ lại bệnh viện để làm thêm một số xét nghiệm.", "opts": ["A. have kept", "B. is keeping", "C. has been kept", "D. was supposed to keep"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. has been kept</div><div class=\"ex-card mb-2\">Mary's aunt<b>has been kept</b>in hospital for some more tests.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Dì của Mary đang được giữ lại bệnh viện để làm thêm một số xét nghiệm.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. have kept</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số ít \"Mary's aunt\" không đi với \"have\" (số nhiều); đây cũng là dạng chủ động sai nghĩa.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is keeping</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"Mary's aunt\" là người ĐƯỢC giữ lại bệnh viện (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. has been kept</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Mary's aunt\" là người được bệnh viện giữ lại, việc này còn liên quan đến hiện tại → hiện tại hoàn thành bị động: has been kept.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. was supposed to keep</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, và về nghĩa cũng không đúng — dì của Mary không phải là người ĐI giữ ai đó lại.</span></div>"}, {"id": 24, "type": "fill", "q": "From the 4th to the 18th of next month, contemporary glass and ceramics__________at the Fenny Lodge Gallery.", "vi": "Từ ngày 4 đến ngày 18 tháng sau, đồ gốm sứ và thủy tinh đương đại sẽ được trưng bày tại Phòng trưng bày Fenny Lodge.", "opts": ["A. will have been displaying", "B. have been displayed", "C. had been displayed", "D. will be displayed"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. will be displayed</div><div class=\"ex-card mb-2\">From the 4th to the 18th of next month, contemporary glass and ceramics<b>will be displayed</b>at the Fenny Lodge Gallery.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Từ ngày 4 đến ngày 18 tháng sau, đồ gốm sứ và thủy tinh đương đại sẽ được trưng bày tại Phòng trưng bày Fenny Lodge.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Tương lai đơn (S + will + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. will have been displaying</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"will have been displaying\" (tương lai hoàn thành tiếp diễn, chủ động) không đúng dạng bị động cần thiết.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. have been displayed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have been displayed\" (hiện tại hoàn thành) không phù hợp với mốc thời gian rõ ràng ở TƯƠNG LAI (\"next month\").</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. had been displayed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been displayed\" (quá khứ hoàn thành) không phù hợp với mốc thời gian ở tương lai.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. will be displayed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Mốc thời gian trong tương lai (\"next month\") + đồ vật ĐƯỢC trưng bày → tương lai đơn bị động: will be displayed.</span></div>"}, {"id": 25, "type": "fill", "q": "The lounge carpet__________after Ralf__________some bleach on it.", "vi": "Tấm thảm phòng khách đã bị hỏng sau khi Ralf làm đổ thuốc tẩy lên nó.", "opts": ["A. is ruined/was spilling", "B. was ruined/had spilt", "C. has been ruined/was spilt", "D. has ruined/had spilt"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. was ruined/had spilt</div><div class=\"ex-card mb-2\">The lounge carpet<b>was ruined/had spilt</b>after Ralf<b>was ruined/had spilt</b>some bleach on it.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tấm thảm phòng khách đã bị hỏng sau khi Ralf làm đổ thuốc tẩy lên nó.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ hoàn thành (S + had + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. is ruined/was spilling</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với ngữ cảnh hoàn toàn ở quá khứ; \"was spilling\" (chủ động tiếp diễn) cũng không hợp lý ở đây.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. was ruined/had spilt</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Tấm thảm bị hỏng (quá khứ đơn, bị động: was ruined) SAU KHI Ralf làm đổ thuốc tẩy (hành động xảy ra TRƯỚC đó, chủ động, quá khứ hoàn thành: had spilt).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has been ruined/was spilt</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been ruined\" (hiện tại hoàn thành) không khớp thì với vế sau ở quá khứ đơn \"was spilt\", và trình tự thời gian (before/after) đòi hỏi quá khứ hoàn thành cho hành động xảy ra trước.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. has ruined/had spilt</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has ruined\" là dạng chủ động sai (tấm thảm không tự làm hỏng chính nó), cần bị động \"was ruined\".</span></div>"}, {"id": 26, "type": "fill", "q": "What time__________their papers__________by the boys?", "vi": "Mấy giờ thì bài làm của các bạn nam có thể được nộp?", "opts": ["A. can/hand in", "B. can/be handed in", "C. can be/handed in", "D. can/be hand"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. can/be handed in</div><div class=\"ex-card mb-2\">What time<b>can/be handed in</b>their papers<b>can/be handed in</b>by the boys?</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Mấy giờ thì bài làm của các bạn nam có thể được nộp?</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. can/hand in</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (hand in), trong khi \"their papers\" là vật ĐƯỢC nộp (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. can/be handed in</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Câu hỏi với modal bị động: What time + can + S + be + Vp2 (+ by...) → can their papers be handed in.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. can be/handed in</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì trật tự từ sai — \"can\" phải đứng ngay sau từ để hỏi \"What time\", trước chủ ngữ, không tách rời khỏi \"be\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. can/be hand</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu Vp2 đầy đủ — phải là \"be handed in\", không phải \"be hand\".</span></div>"}, {"id": 27, "type": "fill", "q": "This year a woman____President of Finland for the first time in the country's history.", "vi": "Năm nay lần đầu tiên trong lịch sử đất nước, một người phụ nữ đã được bầu làm Tổng thống Phần Lan.", "opts": ["A. is elected", "B. was elected", "C. has elected", "D. elected"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. was elected</div><div class=\"ex-card mb-2\">This year a woman<b>was elected</b>President of Finland for the first time in the country's history.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Năm nay lần đầu tiên trong lịch sử đất nước, một người phụ nữ đã được bầu làm Tổng thống Phần Lan.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. is elected</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"is elected\" (hiện tại đơn) không nhấn mạnh được đây là một sự kiện xảy ra (đã hoàn tất) trong \"this year\" (mang tính quá khứ gần).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. was elected</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Sự kiện lịch sử cụ thể đã xảy ra trong năm nay (coi như đã hoàn tất) → quá khứ đơn bị động: was elected.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has elected</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has elected\" là dạng chủ động, không đúng nghĩa (người phụ nữ là người ĐƯỢC bầu, không phải người đi bầu).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. elected</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, không đúng nghĩa cần bị động.</span></div>"}, {"id": 28, "type": "fill", "q": "China__________to have extensive petroleum reserves, both on land and offshore.", "vi": "Trung Quốc được cho là có trữ lượng dầu mỏ lớn, cả trên đất liền lẫn ngoài khơi.", "opts": ["A. believes", "B. has believed", "C. will believe", "D. is believed"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. is believed</div><div class=\"ex-card mb-2\">China<b>is believed</b>to have extensive petroleum reserves, both on land and offshore.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Trung Quốc được cho là có trữ lượng dầu mỏ lớn, cả trên đất liền lẫn ngoài khơi.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — động từ chỉ quan điểm: S + be + said/believed... + to V</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. believes</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"China\" là đối tượng ĐƯỢC người ta tin là có trữ lượng dầu (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. has believed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has believed\" là dạng chủ động, không đúng nghĩa (China không phải chủ thể đi tin điều gì ở đây).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. will believe</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì tương lai không phù hợp và đây vẫn là dạng chủ động sai nghĩa.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. is believed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc bị động với động từ chỉ quan điểm: S + be + believed + to V → is believed to have (extensive reserves).</span></div>"}, {"id": 29, "type": "fill", "q": "Since Bernard__________from the bank, he__________unable to find another job.", "vi": "Kể từ khi Bernard bị sa thải khỏi ngân hàng, anh ấy đã không thể tìm được công việc khác.", "opts": ["A. was dismissed/has been", "B. used to be dismissed/is", "C. has been dismissed/had been", "D. had been dismissing/was"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. was dismissed/has been</div><div class=\"ex-card mb-2\">Since Bernard<b>was dismissed/has been</b>from the bank, he<b>was dismissed/has been</b>unable to find another job.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Kể từ khi Bernard bị sa thải khỏi ngân hàng, anh ấy đã không thể tìm được công việc khác.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. was dismissed/has been</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Mệnh đề \"since\" dùng quá khứ đơn bị động cho sự việc xảy ra một lần (was dismissed - bị sa thải); mệnh đề chính dùng hiện tại hoàn thành cho trạng thái kéo dài đến hiện tại (has been unable).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. used to be dismissed/is</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"used to be dismissed\" (thói quen lặp lại trong quá khứ) không phù hợp với một sự việc xảy ra MỘT LẦN (bị sa thải).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. has been dismissed/had been</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"has been dismissed\" trong mệnh đề \"since\" không tự nhiên bằng quá khứ đơn cho một sự việc mốc thời gian; \"had been\" ở vế sau cũng không phù hợp (cần hiện tại hoàn thành để nối với hiện tại).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. had been dismissing/was</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had been dismissing\" (quá khứ hoàn thành tiếp diễn, chủ động) hoàn toàn sai nghĩa và cấu trúc.</span></div>"}, {"id": 30, "type": "fill", "q": "By the time we__________, all the covered seats__________.", "vi": "Vào lúc chúng tôi đến nơi, tất cả các ghế có mái che đã bị chiếm hết rồi.", "opts": ["A. arrive/might have occupied", "B. are arriving/will occupy", "C. arrived/had been occupied", "D. were arriving/have been occupied"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. arrived/had been occupied</div><div class=\"ex-card mb-2\">By the time we<b>arrived/had been occupied</b>, all the covered seats<b>arrived/had been occupied</b>.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Vào lúc chúng tôi đến nơi, tất cả các ghế có mái che đã bị chiếm hết rồi.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ hoàn thành (S + had + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. arrive/might have occupied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"by the time\" + một hành động đã xảy ra rồi (chiếm ghế trước) đòi hỏi quá khứ đơn ở mệnh đề thời gian và quá khứ hoàn thành ở mệnh đề chính, không phải hiện tại.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. are arriving/will occupy</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại tiếp diễn không phù hợp với cấu trúc \"by the time\" chỉ một mốc đã xảy ra, và \"will occupy\" (chủ động, tương lai) sai nghĩa.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. arrived/had been occupied</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"By the time\" + quá khứ đơn (arrived) ở mệnh đề thời gian; hành động chiếm ghế xảy ra TRƯỚC đó → quá khứ hoàn thành bị động: had been occupied.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. were arriving/have been occupied</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"were arriving\" (quá khứ tiếp diễn) không phù hợp với cấu trúc \"by the time\", và \"have been occupied\" (hiện tại hoàn thành) không khớp thì với ngữ cảnh hoàn toàn quá khứ.</span></div>"}, {"id": 31, "type": "fill", "q": "Before the UN sanctions__________, 60 to 80 percent of our crude oil__________from Iraq.", "vi": "Trước khi các lệnh trừng phạt của Liên Hợp Quốc được áp đặt, 60 đến 80 phần trăm lượng dầu thô của chúng tôi đã được nhập từ Iraq.", "opts": ["A. imposed/will be obtained", "B. are being imposed/have been obtained", "C. were imposing/have obtained", "D. were imposed/had been obtained"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. were imposed/had been obtained</div><div class=\"ex-card mb-2\">Before the UN sanctions<b>were imposed/had been obtained</b>, 60 to 80 percent of our crude oil<b>were imposed/had been obtained</b>from Iraq.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Trước khi các lệnh trừng phạt của Liên Hợp Quốc được áp đặt, 60 đến 80 phần trăm lượng dầu thô của chúng tôi đã được nhập từ Iraq.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ hoàn thành (S + had + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. imposed/will be obtained</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (imposed) trong khi lệnh trừng phạt là thứ ĐƯỢC áp đặt (cần bị động); \"will be obtained\" thì tương lai cũng không phù hợp ngữ cảnh quá khứ.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. are being imposed/have been obtained</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với ngữ cảnh hoàn toàn ở quá khứ của câu.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. were imposing/have obtained</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"were imposing\" là dạng chủ động sai (lệnh trừng phạt không tự áp đặt); \"have obtained\" (hiện tại hoàn thành, chủ động) cũng không đúng thì và cần bị động.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. were imposed/had been obtained</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"Before\" + quá khứ đơn bị động (were imposed) cho sự kiện mốc; hành động nhập dầu xảy ra TRƯỚC đó, kéo dài → quá khứ hoàn thành bị động: had been obtained.</span></div>"}, {"id": 32, "type": "fill", "q": "Most of the 700 protesters the police__________at Mexico's largest university__________within days.", "vi": "Hầu hết trong số 700 người biểu tình mà cảnh sát đã bắt giữ tại trường đại học lớn nhất Mexico đã được thả tự do trong vòng vài ngày.", "opts": ["A. had arrested/will have freed", "B. arrested/were freed", "C. were arrested/may be freed", "D. are arrested/will be freed"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. arrested/were freed</div><div class=\"ex-card mb-2\">Most of the 700 protesters the police<b>arrested/were freed</b>at Mexico's largest university<b>arrested/were freed</b>within days.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Hầu hết trong số 700 người biểu tình mà cảnh sát đã bắt giữ tại trường đại học lớn nhất Mexico đã được thả tự do trong vòng vài ngày.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Quá khứ đơn (S + was/were + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. had arrested/will have freed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"had arrested\" (quá khứ hoàn thành, chủ động) không phù hợp — cảnh sát là chủ thể bắt giữ (đúng là chủ động) nhưng thì không khớp; \"will have freed\" (tương lai hoàn thành, chủ động) cũng sai vì người biểu tình là đối tượng ĐƯỢC thả (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. arrested/were freed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Mệnh đề quan hệ rút gọn \"(that/who) the police arrested\" — cảnh sát là chủ thể (chủ động, quá khứ đơn: arrested); mệnh đề chính bị động vì người biểu tình ĐƯỢC thả: were freed (quá khứ đơn bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. were arrested/may be freed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"were arrested\" trong mệnh đề quan hệ mâu thuẫn — chủ ngữ ẩn ở đây là \"the police\" (chủ thể bắt giữ, cần chủ động \"arrested\", không phải bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. are arrested/will be freed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì hiện tại không phù hợp với ngữ cảnh một sự kiện đã xảy ra trong quá khứ.</span></div>"}, {"id": 33, "type": "fill", "q": "20 million seahorses, which__________in Chinese medicine, __________from the oceans each year.", "vi": "20 triệu con cá ngựa, vốn được sử dụng trong y học cổ truyền Trung Quốc, bị đánh bắt khỏi các đại dương mỗi năm.", "opts": ["A. will be using/are being taken", "B. can be used/have taken", "C. will be used/must have taken", "D. are used/are taken"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. are used/are taken</div><div class=\"ex-card mb-2\">20 million seahorses, which<b>are used/are taken</b>in Chinese medicine, <b>are used/are taken</b>from the oceans each year.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> 20 triệu con cá ngựa, vốn được sử dụng trong y học cổ truyền Trung Quốc, bị đánh bắt khỏi các đại dương mỗi năm.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. will be using/are being taken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì tương lai không phù hợp với một sự thật đang diễn ra hiện tại (cá ngựa hiện đang được dùng trong y học); \"are being taken\" (tiếp diễn) cũng không phù hợp bằng hiện tại đơn cho một sự thật lặp lại hàng năm.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. can be used/have taken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"can be used\" (modal) không cần thiết ở đây (chỉ là một sự thật, không phải khả năng); \"have taken\" là dạng chủ động sai (cá ngựa là đối tượng bị bắt, cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. will be used/must have taken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì tương lai \"will be used\" không phù hợp một thực tế đang diễn ra; \"must have taken\" (suy đoán quá khứ, chủ động) sai nghĩa và cấu trúc.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ D. are used/are taken</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cả hai đều là sự thật chung, lặp lại hàng năm, cá ngựa là đối tượng bị tác động → hiện tại đơn bị động cho cả hai: are used ... are taken.</span></div>"}, {"id": 34, "type": "fill", "q": "In recent years, the elephant's usefulness for labour and a means of transportation__________by technology.", "vi": "Trong những năm gần đây, sự hữu ích của voi trong lao động và làm phương tiện vận chuyển đã bị công nghệ thay thế/loại bỏ.", "opts": ["A. has been eliminated", "B. will be eliminated", "C. is eliminating", "D. eliminated"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. has been eliminated</div><div class=\"ex-card mb-2\">In recent years, the elephant's usefulness for labour and a means of transportation<b>has been eliminated</b>by technology.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Trong những năm gần đây, sự hữu ích của voi trong lao động và làm phương tiện vận chuyển đã bị công nghệ thay thế/loại bỏ.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại hoàn thành (S + have/has + been + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. has been eliminated</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! \"In recent years\" (trong những năm gần đây, kéo dài đến hiện tại) + \"by technology\" (tác nhân) → hiện tại hoàn thành bị động: has been eliminated.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. will be eliminated</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thì tương lai không phù hợp với \"in recent years\" (đã và đang xảy ra, không phải sẽ xảy ra).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. is eliminating</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động (hiện tại tiếp diễn), trong khi \"usefulness\" là thứ BỊ loại bỏ (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. eliminated</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, và thì quá khứ đơn không phù hợp với \"in recent years\" (cần hiện tại hoàn thành).</span></div>"}, {"id": 35, "type": "fill", "q": "Toshico had her car__________by a mechanic.", "vi": "Toshico đã nhờ thợ máy sửa xe của mình.", "opts": ["A. repair", "B. repaired", "C. be repaired", "D. repairing"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. repaired</div><div class=\"ex-card mb-2\">Toshico had her car<b>repaired</b>by a mechanic.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Toshico đã nhờ thợ máy sửa xe của mình.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — Thể nhờ/bảo: have/get sth done</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. repair</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thể nhờ vả bị động \"have + sth + Vp2\" cần dạng Vp2, không phải V-bare.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. repaired</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Thể nhờ/bảo: S + have + sth + Vp2 (+ by sb) → had her car repaired by a mechanic.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. be repaired</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"have + sth + be + Vp2\" không tồn tại, chỉ cần Vp2 trực tiếp sau tân ngữ.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. repairing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thể nhờ vả với tân ngữ là vật cần Vp2 (repaired), không dùng V-ing (repairing).</span></div>"}, {"id": 36, "type": "fill", "q": "Ellen got Marvin__________her paper.", "vi": "Ellen đã nhờ Marvin đánh máy bài viết của mình.", "opts": ["A. to type", "B. typed", "C. typing", "D. is typed"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. to type</div><div class=\"ex-card mb-2\">Ellen got Marvin<b>to type</b>her paper.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Ellen đã nhờ Marvin đánh máy bài viết của mình.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — Thể nhờ/bảo: have/get sth done</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. to type</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc nhờ ai đó làm gì (chủ động) với GET: S + get + sb + to V → got Marvin to type.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. typed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau \"get + sb\" (nhờ NGƯỜI làm) cần \"to V\", không phải Vp2 (dùng cho \"get + sth + Vp2\" khi tân ngữ là vật).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. typing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"get sb V-ing\" không đúng cho nghĩa nhờ vả này.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. is typed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"to\", và \"is typed\" (bị động) không phù hợp — Marvin là người được nhờ TỰ đánh máy (chủ động).</span></div>"}, {"id": 37, "type": "fill", "q": "We got our house__________last week.", "vi": "Tuần trước chúng tôi đã nhờ người sơn lại nhà.", "opts": ["A. painted", "B. painting", "C. to paint", "D. have painted"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. painted</div><div class=\"ex-card mb-2\">We got our house<b>painted</b>last week.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Tuần trước chúng tôi đã nhờ người sơn lại nhà.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — Thể nhờ/bảo: have/get sth done</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. painted</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Thể nhờ/bảo với GET: S + get + sth + Vp2 → got our house painted.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. painting</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"get + sth\" (vật) cần Vp2, không dùng V-ing (painting).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. to paint</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"to paint\" dùng cho \"get + sb + to V\" (nhờ người), không dùng khi tân ngữ là vật \"our house\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. have painted</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc \"got...have painted\" không tồn tại/không đúng ngữ pháp.</span></div>"}, {"id": 38, "type": "fill", "q": "Dr Byrd is having the students__________a composition.", "vi": "Thầy Byrd đang yêu cầu các sinh viên viết một bài luận.", "opts": ["A. written", "B. wrote", "C. write", "D. writing"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. write</div><div class=\"ex-card mb-2\">Dr Byrd is having the students<b>write</b>a composition.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Thầy Byrd đang yêu cầu các sinh viên viết một bài luận.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động đặc biệt — Thể nhờ/bảo: have/get sth done</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. written</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"have + sb + Vp2\" không đúng cấu trúc — với tân ngữ là NGƯỜI (students), cần V-bare, không phải Vp2.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. wrote</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau \"have + sb\" cần V-bare (nguyên mẫu), không chia thì \"wrote\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ C. write</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc nhờ/yêu cầu ai đó làm gì (chủ động): S + have + sb + V(bare) → is having the students write.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. writing</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì sau \"have + sb\" cần V-bare (write), không dùng V-ing (writing).</span></div>"}, {"id": 39, "type": "fill", "q": "How many languages__________in Canada?", "vi": "Có bao nhiêu ngôn ngữ được nói ở Canada?", "opts": ["A. are spoken", "B. is spoken", "C. spoken", "D. spoke"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. are spoken</div><div class=\"ex-card mb-2\">How many languages<b>are spoken</b>in Canada?</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Có bao nhiêu ngôn ngữ được nói ở Canada?</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Chia thì bị động — Hiện tại đơn (S + am/is/are + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ A. are spoken</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Chủ ngữ số nhiều \"languages\" + sự thật chung → hiện tại đơn bị động: are spoken.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ B. is spoken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì chủ ngữ số nhiều \"languages\" không đi với động từ số ít \"is\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. spoken</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu trợ động từ \"are\", không tạo thành câu hỏi hoàn chỉnh.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. spoke</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì \"spoke\" là quá khứ đơn (chủ động), không phù hợp thì hiện tại và cần bị động.</span></div>"}, {"id": 40, "type": "fill", "q": "The clothes have to__________by my mother every day.", "vi": "Quần áo phải được mẹ tôi giặt mỗi ngày.", "opts": ["A. wash", "B. be washed", "C. being washed", "D. washed"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. be washed</div><div class=\"ex-card mb-2\">The clothes have to<b>be washed</b>by my mother every day.</div><div class=\"mb-2\"><b class=\"text-dark2\">🇻🇳 Dịch nghĩa:</b> Quần áo phải được mẹ tôi giặt mỗi ngày.</div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Thuộc phần lý thuyết:</b> Bị động với động từ khuyết thiếu (S + modal + be + Vp2)</div><div class=\"mb-2\"><b class=\"text-dark2\">🔍 Phân tích từng đáp án:</b></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ A. wash</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì đây là dạng chủ động, trong khi \"the clothes\" là vật ĐƯỢC giặt (cần bị động).</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#f0fff4;color:#155724\"><b>✅ B. be washed</b><br><span style=\"font-weight:400;font-size:13px\">Đúng! Cấu trúc bán khuyết thiếu \"have to\" ở dạng bị động: S + have to + be + Vp2 → have to be washed.</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ C. being washed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì cấu trúc bị động sau \"have to\" cần \"be + Vp2\", không phải \"being + Vp2\".</span></div><div class=\"mb-1 p-2 rounded-lg\" style=\"background:#fff5f5;color:#c0392b\"><b>❌ D. washed</b><br><span style=\"font-weight:400;font-size:13px\">Sai vì thiếu \"be\" trước \"washed\" để tạo thành cấu trúc bị động hoàn chỉnh.</span></div>"}];
